await github.teams.getMembershipForUserInOrg({                 org: 'github',                 team_slug: 'docs',                 username: context.payload.sender.login,               });               // If the user is a Docs team member, we should stop here and not send               // a notification               return             } catch(err) {               // An error will be thrown if the user is not a Docs team member               // If a user is not a Docs team member we should continue and send               // the notification             }             const issueNo = context.number || context.issue.number             // Create an issue in our private repo             await github.issues.create({               owner: 'github',               repo: 'docs-internal',               title: `@${context.payload.sender.login} confirm that \\#${issueNo} should be in the public github/docs repo`,               body: `@${context.payload.sender.login} opened https://github.com/github/docs/issues/${issueNo} publicly in the github/docs repo, instead of the private github/docs-internal repo.\\n\\n@${context.payload.sender.login}, please confirm that this belongs in the public repo and that no sensitive information was disclosed by commenting below and closing the issue.\\n\\nIf this was not intentional and sensitive information was shared, please delete https://github.com/github/docs/issues/${issueNo} and notify us in the \\#docs-open-source channel.\\n\\nThanks! \\n\\n/cc @github/docs @github/docs-engineering`             });             throw new Error('A Hubber opened an issue on the public github/docs repo');       - name: Send Slack notification if a GitHub employee who isn't on the docs team opens an issue in public         if: ${{ failure() && github.repository == 'github/docs' }}         uses: someimportantcompany/github-actions-slack-message@0b470c14b39da4260ed9e3f9a4f1298a74ccdefd         with:           channel: ${{ secrets.DOCS_OPEN_SOURCE_SLACK_CHANNEL_ID 